```class Solution {
public:
    int maximumLengthSubstring(string s) {
        int res = 0, start = 0, count[26] = {0};
        for (int end = 0; end < s.size(); end++) {
            count[s[end] - 'a']++;
            while (count[s[end] - 'a'] > 2) {
                count[s[start] - 'a']--;
                start++;
            }
            res = max(res, end - start + 1);
        }
        return res;
    }
};```
